export function getWordsByExam(exam: ExamType): Word[] {
  return wordBank.filter(w => w.examTags.includes(exam));
}

export function getRandomWord(exam?: ExamType): Word {
  const pool = exam ? getWordsByExam(exam) : wordBank;
  return pool[Math.floor(Math.random() * pool.length)];
}

